الصّادق (علیه السلام)-

عَنْ أَبِی‌عَمْرٍو الزُّبَیْرِیِّ عَنْ أَبِی‌عَبْدِ‌اللَّهِ (علیه السلام) قَالَ قُلْتُ لَهُ أَخْبِرْنِی عَنِ الدُّعَاءِ إِلَی اللَّهِ وَ الْجِهَادِ فِی سَبِیلِهِ أَ هُوَ لِقَوْمٍ لَا یَحِلُّ إِلَّا لَهُمْ وَ لَا یَقُومُ بِهِ إِلَّا مَنْ کَانَ مِنْهُمْ أَمْ هُوَ مُبَاحٌ لِکُلِّ مَنْ وَحَّدَ اللَّهَ عَزَّ‌وَ‌جَلَّ فَقَالَ ذَلِکَ لِقَوْمٍ لَا یَحِلُّ إِلَّا لَهُمْ ... قُلْتُ فَبَیِّنْ لِی یَرْحَمُکَ اللَّهُ قَالَ إِنَّ اللَّهَ تَبَارَکَ‌وَ‌تَعَالَی أَخْبَرَ {نَبِیَّهُ} فِی کِتَابِهِ الدُّعَاءَ إِلَیْهِ وَ وَصَفَ الدُّعَاهًَْ إِلَیْهِ فَجَعَلَ ذَلِکَ لَهُمْ دَرَجَاتٍ یُعَرِّفُ بَعْضُهَا بَعْضاً وَ یُسْتَدَلُّ بِبَعْضِهَا عَلَی بَعْضٍ فَأَخْبَرَ أَنَّهُ تَبَارَکَ‌وَ‌تَعَالَی أَوَّلُ مَنْ دَعَا إِلَی نَفْسِهِ وَ دَعَا إِلَی طَاعَتِهِ وَ اتِّبَاعِ أَمْرِهِ فَبَدَأَ بِنَفْسِهِ ... ثُمَّ ثَنَّی بِرَسُولِهِ ثُمَّ ثَلَّثَ بِالدُّعَاءِ إِلَیْهِ بِکِتَابِه ثُمَّ ذَکَرَ مَنْ أَذِنَ لَهُ فِی الدُّعَاءِ إِلَیْهِ بَعْدَهُ وَ بَعْدَ رَسُولِهِ (صلی الله علیه و آله) فِی کِتَابِهِ فَقَالَ وَ لْتَکُنْ مِنْکُمْ أُمَّةٌ یَدْعُونَ إِلَی الْخَیْرِ وَ یَأْمُرُونَ بِالْمَعْرُوفِ وَ یَنْهَوْنَ عَنِ الْمُنْکَرِ وَ أُولئِکَ هُمُ الْمُفْلِحُونَ ثُمَّ أَخْبَرَ عَنْ هَذِهِ الْأُمَّهًِْ وَ مِمَّنْ هِیَ وَ أَنَّهَا مِنْ ذُرِّیَّهًِْ إِبْرَاهِیمَ (علیه السلام) وَ مِنْ ذُرِّیَّهًِْ إِسْمَاعِیلَ (علیه السلام) الَّذِینَ أَخْبَرَ عَنْهُمْ فِی کِتَابِهِ أَنَّهُ أَذْهَبَ عَنْهُمُ الرِّجْسَ وَ طَهَّرَهُمْ تَطْهِیراً ثُمَّ ذَکَرَ أَتْبَاعَ نَبِیِّهِ (صلی الله علیه و آله) وَ أَتْبَاعَ هَذِهِ الْأُمَّهًِْ الَّتِی وَصَفَهَا فِی کِتَابِهِ بِالْأَمْرِ بِالْمَعْرُوفِ وَ النَّهْیِ عَنِ الْمُنْکَرِ وَ جَعَلَهَا دَاعِیَهًًْ إِلَیْهِ وَ أَذِنَ لَهَا فِی الدُّعَاءِ إِلَیْهِ و حَلَّاهُمْ وَ وَصَفَهُمْ کَیْ لَا یَطْمَعَ فِی اللِّحَاقِ بِهِمْ إِلَّا مَنْ کَانَ مِنْهُم ... ثُمَّ أَخْبَرَ أَنَّهُ اشْتَرَی مِنْ هَؤُلَاءِ الْمُؤْمِنِینَ وَ مَنْ کَانَ عَلَی مِثْلِ صِفَتِهِمْ أَنْفُسَهُمْ وَ أَمْوالَهُمْ بِأَنَّ لَهُمُ الْجَنَّةَ یُقاتِلُونَ فِی سَبِیلِ اللهِ فَیَقْتُلُونَ وَ یُقْتَلُونَ وَعْداً عَلَیْهِ حَقًّا فِی التَّوْراةِ وَ الْإِنْجِیلِ وَ الْقُرْآنِ ثُمَّ ذَکَرَ وَفَاءَهُمْ لَهُ بِعَهْدِهِ وَ مُبَایَعَتِهِ فَقَالَ وَ مَنْ أَوْفی بِعَهْدِهِ مِنَ اللهِ فَاسْتَبْشِرُوا بِبَیْعِکُمُ الَّذِی بایَعْتُمْ بِهِ وَ ذلِکَ هُوَ الْفَوْزُ الْعَظِیمُ فَلَمَّا نَزَلَتْ هَذِهِ الْآیَهًُْ إِنَّ اللهَ اشْتَری مِنَ الْمُؤْمِنِینَ أَنْفُسَهُمْ وَ أَمْوالَهُمْ بِأَنَّ لَهُمُ الْجَنَّةَ قَامَ رَجُلٌ إِلَی النَّبِیِّ (صلی الله علیه و آله) فَقَالَ یَا نَبِیَّ اللَّهِ (صلی الله علیه و آله) أَ رَأَیْتَکَ الرَّجُلُ یَأْخُذُ سَیْفَهُ فَیُقَاتِلُ حَتَّی یُقْتَلَ إِلَّا أَنَّهُ یَقْتَرِفُ مِنْ هَذِهِ الْمَحَارِمِ أَ شَهِیدٌ هُوَ فَأَنْزَلَ اللَّهُ عَزَّ‌وَ‌جَلَّ عَلَی رَسُولِهِ التَّائِبُونَ الْعابِدُونَ الْحامِدُونَ السَّائِحُونَ الرَّاکِعُونَ السَّاجِدُونَ الْآمِرُونَ بِالْمَعْرُوفِ وَ النَّاهُونَ عَنِ الْمُنْکَرِ وَ الْحافِظُونَ لِحُدُودِ اللهِ وَ بَشِّرِ الْمُؤْمِنِینَ فَفَسَّرَ النَّبِیُّ (صلی الله علیه و آله) الْمُجَاهِدِینَ مِنَ الْمُؤْمِنِینَ الَّذِینَ هَذِهِ صِفَتُهُمْ وَ حِلْیَتُهُمْ بِالشَّهَادَهًِْ وَ الْجَنَّهًِْ وَ قَالَ التَّائِبُونَ مِنَ الذُّنُوبِ الْعَابِدُونَ الَّذِینَ لَا یَعْبُدُونَ إِلَّا اللَّهَ وَ لَا یُشْرِکُونَ بِهِ شَیْئاً الْحَامِدُونَ الَّذِینَ یَحْمَدُونَ اللَّهَ عَلَی کُلِّ حَالٍ فِی الشِّدَّهًِْ وَ الرَّخَاءِ السَّائِحُونَ وَ هُمُ الصَّائِمُونَ الرَّاکِعُونَ السَّاجِدُونَ الَّذِینَ یُوَاظِبُونَ عَلَی الصَّلَوَاتِ الْخَمْسِ وَ الْحَافِظُونَ لَهَا وَ الْمُحَافِظُونَ عَلَیْهَا بِرُکُوعِهَا وَ سُجُودِهَا وَ فِی الْخُشُوعِ فِیهَا وَ فِی أَوْقَاتِهَا الْآمِرُونَ بِالْمَعْرُوفِ بَعْدَ ذَلِکَ وَ الْعَامِلُونَ بِهِ وَ النَّاهُونَ عَنِ الْمُنْکَرِ وَ الْمُنْتَهُونَ عَنْهُ قَالَ فَبَشِّرْ مَنْ قُتِلَ وَ هُوَ قَائِمٌ بِهَذِهِ الشُّرُوطِ بِالشَّهَادَهًِْ وَ الْجَنَّهًِْ ثُمَّ أَخْبَرَ تَبَارَکَ‌وَ‌تَعَالَی أَنَّهُ لَمْ یَأْمُرْ بِالْقِتَالِ إِلَّا أَصْحَابَ هَذِهِ الشُّرُوطِ فَقَالَ عَزَّ‌وَ‌جَلَّ أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا وَ إِنَّ اللهَ عَلی نَصْرِهِمْ لَقَدِیرٌ الَّذِینَ أُخْرِجُوا مِنْ دِیارِهِمْ بِغَیْرِ حَقٍّ إِلَّا أَنْ یَقُولُوا رَبُّنَا اللهُ وَ ذَلِکَ أَنَّ جَمِیعَ مَا بَیْنَ السَّمَاءِ وَ الْأَرْضِ لِلَّهِ عَزَّ‌وَ‌جَلَّ وَ لِرَسُولِهِ وَ لِأَتْبَاعِهِمَا مِنَ الْمُؤْمِنِینَ مِنْ أَهْلِ هَذِهِ الصِّفَهًِْ فَمَا کَانَ مِنَ الدُّنْیَا فِی أَیْدِی الْمُشْرِکِینَ وَ الْکُفَّارِ وَ الظَّلَمَهًِْ وَ الْفُجَّارِ مِنْ أَهْلِ الْخِلَافِ لِرَسُول‌اللَّهِ (صلی الله علیه و آله) وَ الْمُوَلِّی عَنْ طَاعَتِهِمَا مِمَّا کَانَ فِی أَیْدِیهِمْ ظَلَمُوا فِیهِ الْمُؤْمِنِینَ مِنْ أَهْلِ هَذِهِ الصِّفَاتِ وَ غَلَبُوهُمْ عَلَیْهِ مِمَّا أَفَاءَ اللَّهُ عَلَی رَسُولِهِ فَهُوَ حَقُّهُمْ أَفَاءَ اللَّهُ عَلَیْهِمْ وَ رَدَّهُ إِلَیْهِمْ وَ إِنَّمَا مَعْنَی الْفَیْءِ کُلُّ مَا صَارَ إِلَی الْمُشْرِکِینَ ثُمَّ رَجَعَ مِمَّا کَانَ قَدْ غُلِبَ عَلَیْهِ أَوْ فِیهِ فَمَا رَجَعَ إِلَی مَکَانِهِ مِنْ قَوْلٍ أَوْ فِعْلٍ فَقَدْ فَاءَ مِثْلُ قَوْلِ اللَّهِ عَزَّ‌وَ‌جَلَّ لِلَّذِینَ یُؤْلُونَ مِنْ نِسائِهِمْ تَرَبُّصُ أَرْبَعَةِ أَشْهُرٍ فَإِنْ فاؤُ فَإِنَّ اللهَ غَفُورٌ رَحِیمٌ أَیْ رَجَعُوا ثُمَّ قَالَ وَ إِنْ عَزَمُوا الطَّلاقَ فَإِنَّ اللهَ سَمِیعٌ عَلِیمٌ وَ قَالَ وَ إِنْ طائِفَتانِ مِنَ الْمُؤْمِنِینَ اقْتَتَلُوا فَأَصْلِحُوا بَیْنَهُما فَإِنْ بَغَتْ إِحْداهُما عَلَی الْأُخْری فَقاتِلُوا الَّتِی تَبْغِی حَتَّی تَفِیءَ إِلی أَمْرِ اللهِ أَیْ تَرْجِعَ فَإِنْ فاءَتْ أَیْ رَجَعَتْ فَأَصْلِحُوا بَیْنَهُما بِالْعَدْلِ وَ أَقْسِطُوا إِنَّ اللهَ یُحِبُّ الْمُقْسِطِینَ یَعْنِی بِقَوْلِهِ تَفِیءَ تَرْجِعَ فَذَلِکَ الدَّلِیلُ عَلَی أَنَّ الْفَیْءَ کُلُّ رَاجِعٍ إِلَی مَکَانٍ قَدْ کَانَ عَلَیْهِ أَوْ فِیهِ وَ یُقَالُ لِلشَّمْسِ إِذَا زَالَتْ قَدْ فَاءَتِ الشَّمْسُ حِینَ یَفِیءُ الْفَیْءُ عِنْدَ رُجُوعِ الشَّمْسِ إِلَی زَوَالِهَا وَ کَذَلِکَ مَا أَفَاءَ اللَّهُ عَلَی الْمُؤْمِنِینَ مِنَ الْکُفَّارِ فَإِنَّمَا هِیَ حُقُوقُ الْمُؤْمِنِینَ رَجَعَتْ إِلَیْهِمْ بَعْدَ ظُلْمِ الْکُفَّارِ إِیَّاهُمْ فَذَلِکَ قَوْلُهُ أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا مَا کَانَ الْمُؤْمِنُونَ أَحَقَّ بِهِ مِنْهُمْ وَ إِنَّمَا أُذِنَ لِلْمُؤْمِنِینَ الَّذِینَ قَامُوا بِشَرَائِطِ الْإِیمَانِ الَّتِی وَصَفْنَاهَا وَ ذَلِکَ أَنَّهُ لَا یَکُونُ مَأْذُوناً لَهُ فِی الْقِتَالِ حَتَّی یَکُونَ مَظْلُوماً وَ لَا یَکُونُ مَظْلُوماً حَتَّی یَکُونَ مُؤْمِناً وَ لَا یَکُونُ مُؤْمِناً حَتَّی یَکُونَ قَائِماً بِشَرَائِطِ الْإِیمَانِ الَّتِی اشْتَرَطَ اللَّهُ عَزَّ‌وَ‌جَلَّ عَلَی الْمُؤْمِنِینَ وَ الْمُجَاهِدِینَ فَإِذَا تَکَامَلَتْ فِیهِ شَرَائِطُ اللَّهِ عَزَّ‌وَ‌جَلَّ کَانَ مُؤْمِناً وَ إِذَا کَانَ مُؤْمِناً کَانَ مَظْلُوماً وَ إِذَا کَانَ مَظْلُوماً کَانَ مَأْذُوناً لَهُ فِی الْجِهَادِ لِقَوْلِهِ عَزَّ‌وَ‌جَلَّ أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا وَ إِنَّ اللهَ عَلی نَصْرِهِمْ لَقَدِیرٌ وَ إِنْ لَمْ یَکُنْ مُسْتَکْمِلًا لِشَرَائِطِ الْإِیمَانِ فَهُوَ ظَالِمٌ مِمَّنْ یَبْغِی وَ یَجِبُ جِهَادُهُ حَتَّی یَتُوبَ وَ لَیْسَ مِثْلُهُ مَأْذُوناً لَهُ فِی الْجِهَادِ وَ الدُّعَاءِ إِلَی اللَّهِ عَزَّ‌وَ‌جَلَّ لِأَنَّهُ لَیْسَ مِنَ الْمُؤْمِنِینَ الْمَظْلُومِینَ الَّذِینَ أُذِنَ لَهُمْ فِی الْقُرْآنِ فِی الْقِتَالِ فَلَمَّا نَزَلَتْ هَذِهِ الْآیَهًُْ أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا فِی الْمُهَاجِرِینَ الَّذِینَ أَخْرَجَهُمْ أَهْلُ مَکَّهًَْ مِنْ دِیَارِهِمْ وَ أَمْوَالِهِمْ أُحِلَّ لَهُمْ جِهَادُهُمْ بِظُلْمِهِمْ إِیَّاهُمْ وَ أُذِنَ لَهُمْ فِی الْقِتَالِ فَقُلْتُ فَهَذِهِ نَزَلَتْ فِی الْمُهَاجِرِینَ بِظُلْمِ مُشْرِکِی أَهْلِ مَکَّهًَْ لَهُمْ فَمَا بَالُهُمْ فِی قِتَالِهِمْ کِسْرَی وَ قَیْصَرَ وَ مَنْ دُونَهُمْ مِنْ مُشْرِکِی قَبَائِلِ الْعَرَبِ فَقَالَ لَوْ کَانَ إِنَّمَا أُذِنَ لَهُمْ فِی قِتَالِ مَنْ ظَلَمَهُمْ مِنْ أَهْلِ مَکَّهًَْ فَقَطْ لَمْ یَکُنْ لَهُمْ إِلَی قِتَالِ جُمُوعِ کِسْرَی وَ قَیْصَرَ وَ غَیْرِ أَهْلِ مَکَّهًَْ مِنْ قَبَائِلِ الْعَرَبِ سَبِیلٌ لِأَنَّ الَّذِینَ ظَلَمُوهُمْ غَیْرُهُمْ وَ إِنَّمَا أُذِنَ لَهُمْ فِی قِتَالِ مَنْ ظَلَمَهُمْ مِنْ أَهْلِ مَکَّهًَْ لِإِخْرَاجِهِمْ إِیَّاهُمْ مِنْ دِیَارِهِمْ وَ أَمْوَالِهِمْ بِغَیْرِ حَقٍّ وَ لَوْ کَانَتِ الْآیَهًُْ إِنَّمَا عَنَتِ الْمُهَاجِرِینَ الَّذِینَ ظَلَمَهُمْ أَهْلُ مَکَّهًَْ کَانَتِ الْآیَهًُْ مُرْتَفِعَهًَْ الْفَرْضِ عَمَّنْ بَعْدَهُمْ إِذَا لَمْ یَبْقَ مِنَ الظَّالِمِینَ وَ الْمَظْلُومِینَ أَحَدٌ وَ کَانَ فَرْضُهَا مَرْفُوعاً عَنِ النَّاسِ بَعْدَهُمْ {إِذَا لَمْ یَبْقَ مِنَ الظَّالِمِینَ وَ الْمَظْلُومِینَ أَحَدٌ} وَ لَیْسَ کَمَا ظَنَنْتَ وَ لَا کَمَا ذَکَرْتَ وَ لَکِنَّ الْمُهَاجِرِینَ ظُلِمُوا مِنْ جِهَتَیْنِ ظَلَمَهُمْ أَهْلُ مَکَّهًَْ بِإِخْرَاجِهِمْ مِنْ دِیَارِهِمْ وَ أَمْوَالِهِمْ فَقَاتَلُوهُمْ بِإِذْنِ اللَّهِ لَهُمْ فِی ذَلِکَ وَ ظَلَمَهُمْ کِسْرَی وَ قَیْصَرُ وَ مَنْ کَانَ دُونَهُمْ مِنْ قَبَائِلِ الْعَرَبِ وَ الْعَجَمِ بِمَا کَانَ فِی أَیْدِیهِمْ مِمَّا کَانَ الْمُؤْمِنُونَ أَحَقَّ بِهِ مِنْهُمْ فَقَدْ قَاتَلُوهُمْ بِإِذْنِ اللَّهِ عَزَّ‌وَ‌جَلَّ لَهُمْ فِی ذَلِکَ وَ بِحُجَّهًِْ هَذِهِ الْآیَهًِْ یُقَاتِلُ مُؤْمِنُو کُلِّ زَمَانٍ وَ إِنَّمَا أَذِنَ اللَّهُ عَزَّ‌وَ‌جَلَّ لِلْمُؤْمِنِینَ الَّذِینَ قَامُوا بِمَا وَصَفَهَا اللَّهُ عَزَّ‌وَ‌جَلَّ مِنَ الشَّرَائِطِ الَّتِی شَرَطَهَا اللَّهُ عَلَی الْمُؤْمِنِینَ فِی الْإِیمَانِ وَ الْجِهَادِ وَ مَنْ کَانَ قَائِماً بِتِلْکَ الشَّرَائِطِ فَهُوَ مُؤْمِنٌ وَ هُوَ مَظْلُومٌ وَ مَأْذُونٌ لَهُ فِی الْجِهَادِ بِذَلِکَ الْمَعْنَی وَ مَنْ کَانَ عَلَی خِلَافِ ذَلِکَ فَهُوَ ظَالِمٌ وَ لَیْسَ مِنَ‌الْمَظْلُومِینَ وَ لَیْسَ بِمَأْذُونٍ لَهُ فِی الْقِتَالِ وَ لَا بِالنَّهْیِ عَنِ الْمُنْکَرِ وَ الْأَمْرِ بِالْمَعْرُوفِ لِأَنَّهُ لَیْسَ مِنْ أَهْلِ ذَلِکَ وَ لَا مَأْذُونٍ لَهُ فِی الدُّعَاءِ إِلَی اللَّهِ عَزَّ‌وَ‌جَلَّ لِأَنَّهُ لَیْسَ یُجَاهِدُ مِثْلُهُ وَ أُمِرَ بِدُعَائِهِ إِلَی اللَّهِ وَ لَا یَکُونُ مُجَاهِداً مَنْ قَدْ أُمِرَ الْمُؤْمِنُونَ بِجِهَادِهِ وَ حَظَرَ الْجِهَادَ عَلَیْهِ وَ مَنَعَهُ مِنْهُ وَ لَا یَکُونُ دَاعِیاً إِلَی اللَّهِ عَزَّ‌وَ‌جَلَّ مَنْ أُمِرَ بِدُعَاءِ مِثْلِهِ إِلَی التَّوْبَهًِْ وَ الْحَقِّ وَ الْأَمْرِ بِالْمَعْرُوفِ وَ النَّهْیِ عَنِ الْمُنْکَرِ وَ لَا یَأْمُرُ بِالْمَعْرُوفِ مَنْ قَدْ أُمِرَ أَنْ یُؤْمَرَ بِهِ وَ لَا یَنْهَی عَنِ الْمُنْکَرِ مَنْ قَدْ أُمِرَ أَنْ یُنْهَی عَنْهُ فَمَنْ کَانَتْ قَدْ تَمَّتْ فِیهِ شَرَائِطُ اللَّهِ عَزَّ‌وَ‌جَلَّ الَّتِی وُصِفَ بِهَا أَهْلُهَا مِنْ أَصْحَابِ النَّبِیِّ (صلی الله علیه و آله) وَ هُوَ مَظْلُومٌ فَهُوَ مَأْذُونٌ لَهُ فِی الْجِهَادِ کَمَا أُذِنَ لَهُمْ فِی الْجِهَادِ لِأَنَّ حُکْمَ اللَّهِ عَزَّ‌وَ‌جَلَّ فِی الْأَوَّلِینَ وَ الْآخِرِینَ وَ فَرَائِضَهُ عَلَیْهِمْ سَوَاءٌ إِلَّا مِنْ عِلَّهًٍْ أَوْ حَادِثٍ یَکُونُ وَ الْأَوَّلُونَ وَ الْآخِرُونَ أَیْضاً فِی مَنْعِ الْحَوَادِثِ شُرَکَاءُ وَ الْفَرَائِضُ عَلَیْهِمْ وَاحِدَهًٌْ یُسْأَلُ الْآخِرُونَ عَنْ أَدَاءِ الْفَرَائِضِ عَمَّا یُسْأَلُ عَنْهُ الْأَوَّلُونَ وَ یُحَاسَبُونَ عَمَّا بِهِ یُحَاسَبُونَ وَ مَنْ لَمْ یَکُنْ عَلَی صِفَهًِْ مَنْ أَذِنَ اللَّهُ لَهُ فِی الْجِهَادِ مِنَ الْمُؤْمِنِینَ فَلَیْسَ مِنْ أَهْلِ الْجِهَادِ وَ لَیْسَ بِمَأْذُونٍ لَهُ فِیهِ حَتَّی یَفِیءَ بِمَا شَرَطَ اللَّهُ عَزَّ‌وَ‌جَلَّ عَلَیْهِ فَإِذَا تَکَامَلَتْ فِیهِ شَرَائِطُ اللَّهِ عَزَّ‌وَ‌جَلَّ عَلَی الْمُؤْمِنِینَ وَ الْمُجَاهِدِینَ فَهُوَ مِنَ الْمَأْذُونِینَ لَهُمْ فِی الْجِهَادِ فَلْیَتَّقِ اللَّهَ عَزَّ‌وَ‌جَلَّ عَبْدٌ وَ لَا یَغْتَرَّ بِالْأَمَانِیِّ الَّتِی نَهَی اللَّهُ عَزَّ‌وَ‌جَلَّ عَنْهَا مِنْ هَذِهِ الْأَحَادِیثِ الْکَاذِبَهًِْ عَلَی اللَّهِ الَّتِی یُکَذِّبُهَا الْقُرْآنُ وَ یَتَبَرَّأُ مِنْهَا وَ مِنْ حَمَلَتِهَا وَ رُوَاتِهَا وَ لَا یَقْدَمُ عَلَی اللَّهِ عَزَّ‌وَ‌جَلَّ بِشُبْهَهًٍْ لَا یُعْذَرُ بِهَا فَإِنَّهُ لَیْسَ وَرَاءَ الْمُتَعَرِّضِ لِلْقَتْلِ فِی سَبِیلِ اللَّهِ مَنْزِلَهًٌْ یُؤْتَی اللَّهُ مِنْ قِبَلِهَا وَ هِیَ غَایَهًُْ الْأَعْمَالِ فِی عِظَمِ قَدْرِهَا فَلْیَحْکُمِ امْرُؤٌ لِنَفْسِهِ وَ لْیُرِهَا کِتَابَ اللَّهِ عَ-زَّ‌وَ‌جَلَّ وَ یَعْرِضُ-هَا عَلَیْهِ فَإِنَّهُ لَا أَحَدَ أَعْرَفُ بِالْمَرْءِ مِنْ نَفْسِ-هِ فَإِنْ وَجَدَهَا قَائِمَهًًْ بِمَا شَرَطَ اللَّهُ عَلَیْهِ فِی الْجِهَادِ فَلْیُقْدِمْ عَلَی الْجِهَادِ وَ إِنْ عَلِمَ تَقْصِیراً فَلْیُصْلِحْهَا وَ لْیُقِمْهَا عَلَی مَا فَرَضَ اللَّهُ عَلَیْهَا مِنَ الْجِهَادِ ثُمَّ لْیُقْدِمْ بِهَا وَ هِیَ طَاهِرَهًٌْ مُطَهَّرَهًٌْ مِنْ کُلِّ دَنَسٍ یَحُولُ بَیْنَهَا وَ بَیْنَ جِهَادِهَا وَ لَسْنَا نَقُولُ لِمَنْ أَرَادَ الْجِهَادَ وَ هُوَ عَلَی خِلَافِ مَا وَصَفْنَا مِنْ شَرَائِطِ اللَّهِ عَزَّ‌وَ‌جَلَّ عَلَی الْمُؤْمِنِینَ وَ الْمُجَاهِدِینَ لَا تُجَاهِدُوا وَ لَکِنْ نَقُولُ قَدْ عَلَّمْنَاکُمْ مَا شَرَطَ اللَّهُ عَزَّ‌وَ‌جَلَّ عَلَی أَهْلِ الْجِهَادِ الَّذِینَ بَایَعَهُمْ وَ اشْتَرَی مِنْهُمْ أَنْفُسَهُمْ وَ أَمْوَالَهُمْ بِالْجِنَانِ فَلْیُصْلِحِ امْرُؤٌ مَا عَلِمَ مِنْ نَفْسِهِ مِنْ تَقْصِیرٍ عَنْ ذَلِکَ وَ لْیَعْرِضْهَا عَلَی شَرَائِطِ اللَّهِ فَإِنْ رَأَی أَنَّهُ قَدْ وَفَی بِهَا وَ تَکَامَلَتْ فِیهِ فَإِنَّهُ مِمَّنْ أَذِنَ اللَّهُ عَزَّ‌وَ‌جَلَّ لَهُ فِی الْجِهَادِ فَإِنْ أَبَی أَنْ لَا یَکُونَ مُجَاهِداً عَلَی مَا فِیهِ مِنَ الْإِصْرَارِ عَلَی الْمَعَاصِی وَ الْمَحَارِمِ وَ الْإِقْدَامِ عَلَی الْجِهَادِ بِالتَّخْبِیطِ وَ الْعَمَی وَ الْقُدُومِ عَلَی اللَّهِ عَزَّ‌وَ‌جَلَّ بِالْجَهْلِ وَ الرِّوَایَاتِ الْکَاذِبَهًِْ فَلَقَدْ لَعَمْرِی جَاءَ الْأَثَرُ فِیمَنْ فَعَلَ هَذَا الْفِعْلَ إِنَّ اللَّهَ عَزَّ‌وَ‌جَلَّ یَنْصُرُ هَذَا الدِّینَ بِأَقْوَامٍ لَا خَلَاقَ لَهُمْ فَلْیَتَّقِ اللَّهَ عَزَّ‌وَ‌جَلَّ امْرُؤٌ وَ لْیَحْذَرْ أَنْ یَکُونَ مِنْهُمْ فَقَدْ بَیَّنَ لَکُمْ وَ لَا عُذْرَ لَکُمْ بَعْدَ الْبَیَانِ فِی الْجَهْلِ وَ لَا قُوَّهًَْ إِلَّا بِاللَّهِ وَ حَسْبُنَا اللَّهُ عَلَیْهِ تَوَکَّلْنَا وَ إِلَیْهِ الْمَصِیرُ.

امام صادق (- ابوعمرو زبیری گوید: به امام صادق (عرض کردم: «درباره‌ی دعوت‌کردن بهسوی خدا و جهاد در راه او به من خبر ده که آیا مخصوص گروهی است که این کار فقط برای آنان جایز است و هیچکس نباید به آن اقدام کند جز آن‌ها که از این گروه باشند یا اینکه این کار برای هر یکتاپرستی جایز است»؟ حضرت فرمود: «این کار مخصوص گروهی است که این کار فقط برای آنان جایز است و هیچکس نباید به آن اقدام کند جز کسانی‌که که از این گروه باشند»... عرض‌کردم: «خدا شما را مورد رحمت خویش قرار دهد! این مطلب را کاملاً برایم روشن فرما». حضرت فرمود: «خداوند تبارک‌وتعالی در قرآن، پیامبرش را در مورد دعوت‌کردن به خود با خبر نموده و کسانی که [دیگران را] به‌سوی او دعوت می‌کنند توصیف فرموده و این دعوت‌کردن را برای آن‌ها [شاملِ] درجاتی قرار داده است که هر درجه از آن با درجه‌ی دیگر شناخته می‌شود و برخی، دلیل بر دیگری قرار می‌گیرد؛ و خداوند [در قرآن] خبر داده که خود، اوّلین کسی است که [بندگان را] به‌سوی خود و اطاعت و تبعیّت از اوامرش دعوت می‌کند؛ پس در ابتدا خود این‌کار را آغاز نموده... آن‌گاه در مرتبه‌ی دوّم بهوسیله‌ی رسولش دعوت نموده... و در مرتبه‌ی سوّم بهوسیله‌ی کتابش (قرآن) بهسوی خود دعوت نموده است... سپس در کتابش، کسانی‌که بعد از خود و رسولش به آن‌ها اجازه داده است که بهسوی او دعوت کنند را یاد کرده و فرموده: باید از میان شما، جمعی دعوت به نیکی، و امر به معروف و نهی از منکر کنند! و آن‌ها همان رستگارانند. (

آل‌عمران/۱۰۴

) سپس درباره این گروه و اینکه از چه کسانی هستند، خبر داده [و فرموده] که آن‌ها از نسل ابراهیم و اسماعیل (هستند؛ همانانی‌که در کتابش درباره‌ی آن‌ها فرموده که پلیدی را از آن‌ها دورکرده و آن‌ها را پاک و پاکیزه ساخته است (اشاره به آیه‌ی۳۳ از سوره‌ی احزاب که در مورد اهل بیت (نازل شده است). آنگاه پیروان پیامبرش (و پیروان این گروه را که خداوند به امر به معروف و نهی از منکرکردن، توصیفشانکرده و آن‌ها را دعوت‌کننده به‌سوی خودش قرارداده و اجازه این دعوت‌کردن را به آن‌ها داده، یاد نموده است... سپس به بیان ویژگی‌های این پیروان پرداخته است، تا کسی مدّعی نشود که جزو آنان است مگر کسی که واقعا از ایشان باشد... آن‌گاه خداوند خبر داده که از این مؤمنان و کسانی‌که دارای ویژگی‌های آنان هستند جان‌ها و اموالشان را خریداری کرده: که [در برابرش] بهشت برای آنان باشد؛ [به این گونه که:] در راه خدا پیکار می کنند، می‌کشند و کشته می‌شوند؛ این وعده‌ی حقّی است بر او، که در تورات و انجیل و قرآن ذکر فرموده است. (

توبه/۱۱۱

) سپس وفای بهعهد و پیمان خود نسبت به آن‌ها را بیان کرده و فرمود: و چه کسی از خدا به عهدش وفادارتر است؟! اکنون بشارت باد بر شما، به داد و ستدی که با خدا کرده‌اید و این است آن پیروزی بزرگ. (

توبه/۱۱۱

) هنگامی‌که آیه: خداوند جانها و اموالشان را خریداری میکند که [در برابرش] بهشت برای آنان باشد. (

توبه/۱۱۱

) نازل شد، مردی برخاست و بهطرف پیامبر (آمد و عرض‌کرد: «ای پیامبر خدا (! به نظر شما مردی که شمشیرش را برگرفته و میجنگد تا آنکه کشته میشود درحالی‌که مرتکب برخی از گناهان شده شهید است»؟ در این‌هنگام، خداوند عزّوجلّ این آیه را بر رسولش نازل فرمود: توبه‌کنندگان، عبادت‌کاران، سپاس‌گویان، سیاحت‌کنندگان، رکوع‌کنندگان، سجده‌آوران، آمران به معروف، نهی‌کنندگان از منکر و حافظان حدود [و مرزهای] الهی، [مؤمنان حقیقی‌اند] و بشارت ده به [اینچنین] مؤمنان! (

توبه/۱۱۲

) پیامبر ([نیز] مؤمنان مجاهد که دارای این ویژگی‌ها هستند را به شهادت و بهشت بشارت داده و فرمود: «توبه‌کنندگان از گناه، عبادتکنندگانی هستند که جز خدا چیزی را عبادت نمیکنند و چیزی را شریک او نمیگیرند؛ سپاس‌گویان آنهایی هستند که در هرحال از سختی و آسایش، خدا را سپاس میگویند؛ سیاحتکنندگان، همان روزه‌دارانند و رکوعکنندگان و سجده‌آوران، کسانی هستند که بر نمازهای پنجگانه مواظبت میکنند و در انجام آن‌ها کوشا هستند و با [به‌جا آوردنِ] رکوع و سجود و با فروتنی در نمازها و اوقات نماز، بر نمازهایشان مداومت می‌کنند؛ اینان بعد از انجام عبادت، امر به خوبی‌ها کرده و خود نیز به آن‌ها عمل می‌کنند و از زشتی‌ها بازمی‌دارند و خود نیز از آن‌ها دوری می‌نمایند»؛ خداوند [به پیامبر (] فرمود: «هرکس که این ویژگی‌ها را داشته باشد و کشته شود را به شهادت و بهشت بشارت ده». آنگاه خداوند تبارک و تعالی خبر داد که فقط کسانی را مأمور به جهاد نموده که دارای این شرائط هستند و فرمود: به کسانی که جنگ بر آنان تحمیل گردیده، اجازه جهاد داده شده است چرا که مورد ستم قرار گرفته‌اند و خدا بر یاری آن‌ها تواناست. همانها که از خانه و شهر خود، به ناحق رانده شدند، جز اینکه می‌گفتند: «پروردگار ما، خدای یکتاست!» (

حج/۴۰-۳۹

) و این [که می‌فرماید مورد ستم قرار گرفته و به ناحق از دیار خود رانده شده‌اند] برای خاطر آن است که همه‌ی آنچه میان آسمان و زمین قرار دارد برای خدا و رسولش و پیروان مؤمنشان است که دارای این صفات هستند؛ در نتیجه آنچه از دنیا در دست مشرکان، کافران، ستمگران، بدکارانی که با رسول‌خدا (مخالفت می‌کنند و کسانی‌که روی‌گردان از پیروی خدا و رسولش (هستند، قرار دارد بهوسیله‌ی [تصاحب‌کردنِ] آن‌ها، بر مؤمنانی‌که دارای این ویژگی‌ها هستند ستم روا داشته و بر آن‌ها در آنچه که خدا بر رسولش ([به‌عنوان فَیء] ارزانی داشته غلبه کردهاند؛ پس تمامی این‌ها حقّ آن مؤمنان است که خدا بر آن‌ها ارزانی داشته و به ایشان بازگردانده است. و «فَیء» عبارت است از هر مالی‌که [در ابتدا] به‌دست مشرکان افتاده و سپس [به‌دست مؤمنان که مالکان حقیقی آن هستند] بازگشته که عبارت‌است از اموالی‌که مسلمانان [بدون تاخت و تاز] بر آن‌ها دست یافته و یا سرزمینی‌که بر آن مسلّط شده‌اند؛ پس [در زبان عربی] به هر سخن یا کاری‌که به جایگاه [اصلی]اش بازگردد، می‌گویند «فاءَ»؛ مانند این سخن خداوند عزّوجلّ [که فرموده:] برای کسانی‌که سوگند یاد می‌کنند [که از آمیزش] با زنان خود دوری گزینند، [شرعاً] چهار ماه مهلت است؛ چنانچه [در این مدت به آنچه مقتضای زناشویی است] بازگشتند [گناهی بر آنان نیست] زیرا خدا بسیار آمرزنده و مهربان است. (

بقره/۲۲۶

) [که در این‌جا فاؤُ] یعنی بازگشتند. سپس [در ادامه] فرموده: و اگر تصمیم به جدایی گرفتند، خداوند شنوا و داناست. (

بقره/۲۲۷

) و [در آیه‌ای دیگر] فرم-وده: و هر گاه دو گ-روه از م-ؤمنان با هم به نزاع و جنگ پردازند، آن‌ها را آشتی دهید و اگر یکی از آن‌دو بر دیگری تجاوز کند، با گروه متجاوز پیکار کنید تا به فرمان خدا بازگردد [که در این‌جا تَفِیءَ]یعنی بازگردد؛ فَإِنْ فاءَتْ یعنی اگر بازگشت، در میان آن دو به عدالت صلح برقرار سازید و عدالت پیشه کنید که خداوند عدالت‌پیشگان را دوست می‌دارد. (

حجرات/۹

) که مراد از تَفِیءَ، تَرجِعَ (بازگردد) می‌باشد. و این [آیات] نشاندهنده‌ی این است که «فَیء» هر چیزی است که به حالت یا جایگاه گذشته‌اش بازگردد؛ و هنگامی‌که خورشید از میانه‌ی آسمان به‌سوی مغرب مایل شود می‌گویند: «قَدْ فاءَتِ الشَّمسُ» و آن، هنگامی است که سایه [به‌دلیل حرکت خورشید به‌سمت مغرب] از مغرب به‌سمت مشرق کشیده می‌شود و خورشید به زوالش بازگشت می‌کند؛ هم‌چنین است آنچه خداوند از کافران به مؤمنان بازمی‌گرداند، تمامی آن‌ها حق‌ّ مؤمنان است که بعد از ستمی که کافران بر ایشان روا می‌دارند، به ایشان بازمی‌گردد؛ این همان سخن خداوند است [که فرموده:] أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا؛ چنین نیست که همه‌ی مؤمنان، شایسته‌ی جنگ با کافران باشند بلکه فقط به مؤمنانی اجازه داده شده که دارای شرایط ایمان هستند، یعنی همان شرایطی که بیان کردیم؛ دلیل این مطلب آن است‌که کسی اجازه‌ی جهاد ندارد مگر اینکه مظلوم واقع شده باشد و کسی مظلوم واقع نمی‌شود مگر اینکه مؤمن باشد و کسی مؤمن نیست مگر اینکه دارای شرایط ایمان باشد، یعنی همان شرایطی‌که خداوند عزّوجلّ برای مؤمنان و مجاهدان قرار داده است؛ پس هرگاه شرایط خداوند عزّوجلّ در کسی کامل شد او مؤمن است و چون مؤمن شد مظلوم خواهد بود و چون مظلوم باشد اجازه‌ی جهاد پیدا خواهد نمود؛ به‌خاطر این سخن خداوند عزّوجلّ [که فرموده:] أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا وَ إِنَّ اللهَ عَلی نَصْرِهِمْ لَقَدِیرٌ. و اگر کسی تمامی شرایط ایمان را دارا نباشد ظالمی است که سرکشی می‌کند و تا زمانی‌که توبه نماید پیکار با او واجب است و چنین کسی، اجازه‌ی جهاد و دعوت‌کردن به‌سوی خداوند عزّوجلّ را ندارد چراکه او از جمله‌ی مؤمنان مظلومی که در قرآن به آن‌ها اجازه‌ی جهاد داده شده است، نمی‌باشد. هنگامی‌که آیه‌ی أُذِنَ لِلَّذِینَ یُقاتَلُونَ بِأَنَّهُمْ ظُلِمُوا درباره‌ی مهاجرانی که اهل مکّه آن‌ها را از شهر و دارایی‌هایشان بیرون کرده بودند نازل شد، جهاد با اهل مکّه به‌خاطر ظلمی‌که بر مهاجران روا داشته بودند، برای مهاجران حلال گردید و اجازه‌ی جهاد به آن‌ها داده شد». [أبوعمرو زبیری گوید:] من گفتم: «این آیه درباره‌ی مهاجرین بهخاطر ظلمی که مشرکان مکّه به آن‌ها کرده بودند نازل شد، پس چرا مسلمانان با کسری (پادشاه ایران)، قیصر (پادشاه روم) و با مشرکانی از قبایل عرب غیر از مشرکان مکّه نیز پیکار کردند»؟! امام (فرمود: «اگر فقط برای پیکار با اهل مکّه که به آنان ظلم کرده بودند به آنان اجازه داده شده بود دیگر حق نداشتند با لشکر کسری، قیصر و قبایل دیگر عرب غیر از اهل مکّه پیکار کنند؛ زیرا آن‌ها که ستم کرده بودند غیر از اینها بودند و آن‌ها فقط مجاز بودند با اهل مکّه که به ایشان ستم کرده بودند پیکار کنند چون آن‌ها را به ناحق از شهر و دارایی‌هایشان بیرون کرده بودند و اگر منظور آیه فقط مهاجرین که اهل مکّه بر آن‌ها ستم روا داشتند، میبود، دیگر هنگامیکه کسی از آن ظالمان و آن مظلومان باقی نمانده بود وجوبی برای آیه باقی نمی‌ماند و وجوب آن از مردمِ بعد از آن‌ها برداشته میشد؛ ولی این‌گونه که تو گم-ان کردی و گف-تی نیست؛ بلکه مهاج-رین از دو جهت مورد ستم واقع شدند؛ اهل مکّه با بیرون‌کردن آن‌ها از شهر و دارایی‌هایشان به آن‌ها ظلم کردند که مهاجرین با اجازه‌ی خدا با اینها در این مورد پیکار کردند؛ کسری، قیصر و دیگر قبایل عرب [نیز] با در اختیار گرفتن آنچه مؤمنان به در اختیار گرفتنش سزاوارتر بودند به مؤمنان ظلم می‌کردند که مؤمنان با اذن خداوند عزّوجلّ با آن‌ها [نیز] به پیکار برخاستند؛ و با تکیه بر این آیه، مؤمنان در هر زمان می‌توانند [با ظالمان] پیکار کنند و خداوند عزّوجلّ به تمامی مؤمنانی‌که دارای شرایط ایمان باشند اجازه [پیکار] داده، یعنی همان شرایطی‌که خداوند عزّوجلّ برای مؤمنان و مجاهدان قرار داده است؛ و هرکس دارای این شرایط باشد او مؤمن و مظلوم است و به او در جهاد به این معنا اجازه داده شده است؛ و هرکس دارای آن شرایط نباشد ظالم است و از مظلومان به حساب نمیآید و نه اجازه‌ی پیکار دارد و نه اجازه‌ی امر بهمعروف و نهی ازمنکر کردن؛ زیرا چنین کسی نه صلاحیّت چنین کاری را دارد و نه اجازه دارد که به‌سوی خداوند عزّوجلّ دعوت کند و چون کسی همچون او به جهاد برنمی‌خیزد با اینکه لازم است دیگران او را به‌سوی خداوند دعوت کنند و کسی‌که مؤمنان، مأمور به پیکار با او هستند و خداوند او را از جهادکردن بازداشته است مجاهد نخواهد بود و کسی‌که دیگران وظیفه دارند او را به‌سوی توبه و حقیقت و امر به معروف و نهی از منکر دعوت کنند نمی‌تواند دعوت‌کننده به‌سوی خداوند عزّوجلّ باشد و کسی‌که دیگران وظیفه دارند او را امر به‌معروف کنند نمی‌تواند خود، امرکننده به معروف باشد و کسی‌که دیگران وظیفه دارند او را نهی از منکر کنند نمی‌تواند خود، نهی‌کننده از منکر باشد. پس هرکس‌که به‌طور کامل، شرایط خداوند عزّوجلّ - یعنی همان شرایطی‌که یاران پیامبر (دارای آن‌ها بودند - را داشته باشد و در عین‌حال، مظلوم باشد اجازه‌ی جهاد دارد، همچنان‌که خداوند به یاران پیامبر (اجازه‌ی جهاد داد؛ چراکه حکم خداوند عزّوجلّ و واجبات او درباره‌ِی اوّلین مسلمانان و آخرین آن‌ها یکی است مگر اینکه بیماری یا پیشامدی، حکم و واجب الهی را تغییر دهد که در این‌صورت اولین و آخرین در تغییر احکام به‌وسیله‌ِی پیشامدها نیز مشترکند و واجباتشان یکی است، از آخرین آن‌ها همان سؤالاتی خواهد شد که از اولین پرسیده می‌شود و هر دو به یک چیز محاسبه خواهند گردید. و هرکس‌که ویژگی مؤمنانی‌که خداوند به آن‌ها اجازه‌ی جهاد داده را دارا نباشد از اهل جهاد نخواهد بود و اجازه‌ی چنین کاری را ندارد تا زمانی‌که به شرایط خداوند عزّوجلّ بازگردد و هرگاه شرایطی‌که خداوند عزّوجلّ برای مؤمنان و مجاهدان در نظر گرفته در او به‌طور کامل ایجاد گردد او نیز از کسانی خواهد بود که اجازه‌ی جهاد دارند. پس هر بنده‌ای باید تقوای الهی پیشه کند و در مورد احادیثی‌که بر خدا دروغ بسته می‌شود فریفته‌ی خواهش‌ها[ی نفسانی] که خداوند عزّوجلّ از آن‌ها نهی نموده، نشود - همان احادیثی‌که قرآن آن‌ها را دروغ انگاشته و از آن‌ها، حاملان و نقل‌کنندگانش بیزاری می‌جوید - و با شُبهه‌ای‌که عذری برایش ندارد نسبت به خداوند عزّوجلّ جسارت پیدا نکند، زیرا پیش‌روی کسی‌که خود را [به ناحقّ] در معرض کشته‌شدن در راه خداوند قرار می‌دهد منزلت و جایگاهی وجود ندارد که بتوان به‌وسیله‌ی آن به [درگاه]خداوند تقرّب جست، در حالی‌که تقرّب به [درگاه]خداوند که مقامی بس بلند است هدف نهایی از اعمال نیک می‌باشد. هر انسانی باید در مورد خویشتن داوری کند و خود را بر قرآن عرضه کرده و با آن بسنجد، چراکه هیچکس نسبت به انسان از خودش آگاه‌تر نیست؛ پس اگر شرایطی که خداوند در مورد جهاد برایش بیان داشته را در خود می‌یابد باید اقدام به جهاد کند و اگر در خود، کوتاهی مشاهده کرد باید آن را اصلاح کرده و خود را با شرایط جهاد که خداوند بر او واجب نموده مطابقت دهد و آن‌گاه اقدام به جهاد نماید در حالی‌که از هر آلودگی‌که میان او و جهاد کردنش فاصله می‌اندازد، پاک و پاکیزه باشد. ما (اهل‌بیت) به کسانی‌که قصد جهادکردن دارند ولی شرایطی‌که خداوند عزّوجلّ برای مؤمنان و مجاهدان بیان داشته را دارا نمی‌باشند، نمی‌گوییم که جهاد نکنید، ولی می‌گوییم ما شرایطی‌که خدا برای اهل جهاد قرار داده را به شما آموخته‌ایم، همان اهل جهادی‌که خداوند با آن‌ها پیمان بسته و جان‌ها و اموالشان را در مقابل بهشت از آن‌ها خریداری نموده است؛ حال هرکس باید شرایطی که در خود نمی‌بیند را سامان دهد و خود را بر شرایط الهی عرضه کند، اگر دید که دارای آن شرایط به‌طور کامل است بداند از کسانی است که خداوند عزّوجلّ به آنان اجازه‌ی جهاد داده است؛ و اگر با وجود اینکه بر [انجام] گناهان و محرّمات اصرار دارد، با این‌حال می‌خواهد مجاهد باشد و جاهلانه و کورکورانه، اقدام به جهاد کند و از روی نادانی و توجّه‌کردن به روایات ساختگی، نسبت به [دستوراتِ] خداوند عزّوجلّ جسارت پیدا کند، به جان خودم سوگند! نتیجه‌ی کار چنین انسانی این است‌که خداوند عزّوجلّ دین اسلام را به‌وسیله‌ی گروه‌هایی‌که بهره‌ای [از اسلام] ندارند (یعنی کافران و مشرکان) یاری کند؛ پس هرکس باید از خداوند پروا داشته و از اینکه جزو چنین مجاهدانی باشد، پرهیز نماید که خداوند [این حقیقت را] برای شما بیان کرده و بعد از بیان الهی، شما عذری برای نادانی نخواهید داشت. هیچ نیرویی جز از جانب خدا نیست و خدا ما را بس است، فقط بر او توکّل می‌کنیم و بازگشت به سوی اوست».

تفسیر اهل بیت علیهم السلام ج۹، ص۶۷۰

الکافی، ج۵، ص۱۵/ تهذیب الأحکام، ج۶، ص۱۲۹/ وسایل الشیعهًْ، ج۱۵، ص۳۶/ نورالثقلین؛ «حضر» بدل «حظر» و «مأذون» بدل «مأذونین»/ مستدرک الوسایل، ج۱۱، ص۱۲۴؛ «بتفاوت»

